import type { PeriodJobStatusDto } from '../services/kt/models';

export interface PollPeriodJobOptions {
  intervalMs?: number;
  maxAttempts?: number;
}

const TERMINAL = new Set(['Calculated', 'Posted', 'Failed']);

/** Poll GET period-job/status until Calculated, Posted, Failed, or timeout. */
export async function pollPeriodJobStatus(
  getStatus: () => Promise<PeriodJobStatusDto>,
  options?: PollPeriodJobOptions,
): Promise<PeriodJobStatusDto> {
  const intervalMs = options?.intervalMs ?? 1000;
  const maxAttempts = options?.maxAttempts ?? 90;

  for (let attempt = 0; attempt < maxAttempts; attempt += 1) {
    const status = await getStatus();
    if (TERMINAL.has(status.jobStatus)) {
      return status;
    }
    if (status.jobStatus === 'NotRun') {
      return status;
    }
    await new Promise(resolve => setTimeout(resolve, intervalMs));
  }

  throw new Error('PERIOD_JOB_POLL_TIMEOUT');
}
