import type { CarryOverStatusDto, PeriodProcessStatusDto } from '../services/kt/models';

/** Nhãn trạng thái nghiệp vụ cuối kỳ — map status BE → VN */
export function periodProcessStatusLabel(dto: PeriodProcessStatusDto): string {
  const period = `${dto.month}/${dto.year}`;
  switch (dto.status) {
    case 'NotRun':
      return `Chưa chạy — kỳ ${period}`;
    case 'Generated':
      return `Đã tạo ${dto.journalCount} bút toán nháp — kỳ ${period}`;
    case 'Posted':
      return `Đã ghi sổ (${dto.journalCount} bút toán) — kỳ ${period}`;
    default:
      return dto.status ?? '—';
  }
}

/** Nhãn trạng thái async period job */
export function periodJobRunStatusLabel(status: string | undefined): string {
  switch (status) {
    case 'NotRun':
      return 'Chưa chạy';
    case 'Queued':
      return 'Đang chờ xử lý…';
    case 'Processing':
      return 'Đang xử lý…';
    case 'Calculated':
      return 'Đã tạo bút toán nháp';
    case 'Posted':
      return 'Đã ghi sổ';
    case 'Failed':
      return 'Thất bại';
    default:
      return status ?? '—';
  }
}

export function carryOverStatusLabel(dto: CarryOverStatusDto): string {
  if (dto.status === 'Done') {
    return `Đã chuyển số dư sang năm ${dto.targetYear} (${dto.accountCount} tài khoản)`;
  }
  return `Chưa chuyển số dư sang năm ${dto.targetYear}`;
}
